class Solution:
    def sortString(self, s: str) -> str:
        from collections import Counter
        freq = Counter(s)
        result = []
        letters = sorted(freq.keys())
        while sum(freq.values()) > 0:
            for c in letters:
                if freq[c] > 0:
                    result.append(c)
                    freq[c] -= 1
            for c in reversed(letters):
                if freq[c] > 0:
                    result.append(c)
                    freq[c] -= 1
        return ''.join(result)

