class Solution:
    def sortString(self, s: str) -> str:
        freq = [0] * 26
        for c in s:
            freq[ord(c) - ord('a')] += 1
        result = []
        while len(result) < len(s):
            for i in range(26):
                if freq[i] > 0:
                    result.append(chr(ord('a') + i))
                    freq[i] -= 1
            for i in range(25, -1, -1):
                if freq[i] > 0:
                    result.append(chr(ord('a') + i))
                    freq[i] -= 1
        return ''.join(result)

