var sortString = function(s) {
    const freq = new Array(26).fill(0);
    for (const c of s) freq[c.charCodeAt(0) - 97]++;
    const result = [];
    while (result.length < s.length) {
        for (let i = 0; i < 26; i++) if (freq[i] > 0) { result.push(String.fromCharCode(97 + i)); freq[i]--; }
        for (let i = 25; i >= 0; i--) if (freq[i] > 0) { result.push(String.fromCharCode(97 + i)); freq[i]--; }
    }
    return result.join('');
};
